import { Router, Request, Response } from 'express';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { getDb } from '../database/db';
import type { LoginRequest, LoginResponse, JwtPayload, ApiError, User } from '../types';

const router = Router();

// POST /api/auth/login - 用户登录
router.post('/login', async (req: Request, res: Response) => {
  try {
    const { username, password }: LoginRequest = req.body;

    // 参数验证
    if (!username || !password) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '用户名和密码不能为空'
      };
      return res.status(400).json(error);
    }

    const db = getDb();

    // 查询用户
    const user = db.prepare(`
      SELECT id, username, password_hash, email 
      FROM users 
      WHERE username = ?
    `).get(username) as { id: number; username: string; password_hash: string; email: string } | undefined;

    if (!user) {
      const error: ApiError = {
        code: 'USER_NOT_FOUND',
        message: '用户不存在'
      };
      return res.status(401).json(error);
    }

    // 验证密码
    const isValidPassword = await bcrypt.compare(password, user.password_hash);
    if (!isValidPassword) {
      const error: ApiError = {
        code: 'INVALID_PASSWORD',
        message: '密码错误'
      };
      return res.status(401).json(error);
    }

    // 生成JWT token
    const payload: JwtPayload = {
      userId: user.id,
      username: user.username
    };

    const token = jwt.sign(payload, process.env.JWT_SECRET || 'your-secret-key', {
      expiresIn: '24h'
    });

    // 返回用户信息和token
    const response: LoginResponse = {
      token,
      user: {
        id: user.id,
        username: user.username,
        email: user.email
      }
    };

    return res.status(200).json(response);

  } catch (error) {
    console.error('Login error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '服务器内部错误'
    };
    return res.status(500).json(errorResponse);
  }
});

// POST /api/auth/register - 用户注册（可选功能）
router.post('/register', async (req: Request, res: Response) => {
  try {
    const { username, password, email }: { username: string; password: string; email: string } = req.body;

    // 参数验证
    if (!username || !password || !email) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '用户名、密码和邮箱不能为空'
      };
      return res.status(400).json(error);
    }

    const db = getDb();

    // 检查用户是否已存在
    const existingUser = db.prepare('SELECT id FROM users WHERE username = ?').get(username);
    if (existingUser) {
      const error: ApiError = {
        code: 'USER_EXISTS',
        message: '用户名已存在'
      };
      return res.status(409).json(error);
    }

    // 哈希密码
    const saltRounds = 10;
    const passwordHash = await bcrypt.hash(password, saltRounds);

    // 插入新用户
    const result = db.prepare(`
      INSERT INTO users (username, password_hash, email, created_at)
      VALUES (?, ?, ?, datetime('now'))
    `).run(username, passwordHash, email);

    // 生成JWT token
    const payload: JwtPayload = {
      userId: result.lastInsertRowid as number,
      username
    };

    const token = jwt.sign(payload, process.env.JWT_SECRET || 'your-secret-key', {
      expiresIn: '24h'
    });

    const response: LoginResponse = {
      token,
      user: {
        id: result.lastInsertRowid as number,
        username,
        email
      }
    };

    return res.status(201).json(response);

  } catch (error) {
    console.error('Register error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '服务器内部错误'
    };
    return res.status(500).json(errorResponse);
  }
});

// GET /api/auth/me - 获取当前用户信息
router.get('/me', (req: Request, res: Response) => {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      const error: ApiError = {
        code: 'UNAUTHORIZED',
        message: '未提供认证令牌'
      };
      return res.status(401).json(error);
    }

    const token = authHeader.substring(7);
    const payload = jwt.verify(token, process.env.JWT_SECRET || 'your-secret-key') as JwtPayload;

    const db = getDb();
    const user = db.prepare(`
      SELECT id, username, email 
      FROM users 
      WHERE id = ?
    `).get(payload.userId) as User | undefined;

    if (!user) {
      const error: ApiError = {
        code: 'USER_NOT_FOUND',
        message: '用户不存在'
      };
      return res.status(404).json(error);
    }

    return res.status(200).json(user);

  } catch (error) {
    console.error('Get user error:', error);
    const errorResponse: ApiError = {
      code: 'UNAUTHORIZED',
      message: '认证失败'
    };
    return res.status(401).json(errorResponse);
  }
});

export default router;

import { Router, Request, Response } from 'express';
import { getDb } from '../database/db';
import type { ProductQueryParams, ProductListResponse, Product, CreateProductRequest, PaginatedResponse, ApiError } from '../types';

const router = Router();

// GET /api/products - 获取商品列表
router.get('/', (req: Request, res: Response) => {
  try {
    const {
      page = 1,
      limit = 10,
      category
    }: ProductQueryParams = req.query as ProductQueryParams;

    // 确保分页参数有效
    const pageNum = Math.max(1, Number(page));
    const limitNum = Math.min(100, Math.max(1, Number(limit)));
    const offset = (pageNum - 1) * limitNum;

    const db = getDb();

    // 构建查询
    let countSql = 'SELECT COUNT(*) as total FROM products';
    let selectSql = `
      SELECT id, name, description, price, category, image_url, stock, created_at 
      FROM products
    `;
    const params: (string | number)[] = [];

    // 添加分类筛选
    if (category) {
      const whereClause = ' WHERE category = ?';
      countSql += whereClause;
      selectSql += whereClause;
      params.push(category);
    }

    // 获取总数
    const countResult = db.prepare(countSql).get(...params) as { total: number };
    const total = countResult.total;

    // 添加排序和分页
    selectSql += ' ORDER BY created_at DESC LIMIT ? OFFSET ?';
    params.push(limitNum, offset);

    // 执行查询
    const rows = db.prepare(selectSql).all(...params) as {
      id: number;
      name: string;
      description: string;
      price: number;
      category: string;
      image_url: string;
      stock: number;
      created_at: string;
    }[];

    // 转换数据格式
    const products: Product[] = rows.map(row => ({
      id: row.id,
      name: row.name,
      description: row.description,
      price: row.price,
      category: row.category,
      imageUrl: row.image_url,
      stock: row.stock,
      createdAt: row.created_at
    }));

    const response: ProductListResponse = {
      products,
      total,
      page: pageNum,
      limit: limitNum
    };

    return res.status(200).json(response);

  } catch (error) {
    console.error('Get products error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '获取商品列表失败'
    };
    return res.status(500).json(errorResponse);
  }
});

// GET /api/products/:id - 获取单个商品详情
router.get('/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const productId = parseInt(id, 10);

    if (isNaN(productId)) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '无效的商品ID'
      };
      return res.status(400).json(error);
    }

    const db = getDb();
    const row = db.prepare(`
      SELECT id, name, description, price, category, image_url, stock, created_at 
      FROM products 
      WHERE id = ?
    `).get(productId) as {
      id: number;
      name: string;
      description: string;
      price: number;
      category: string;
      image_url: string;
      stock: number;
      created_at: string;
    } | undefined;

    if (!row) {
      const error: ApiError = {
        code: 'PRODUCT_NOT_FOUND',
        message: '商品不存在'
      };
      return res.status(404).json(error);
    }

    const product: Product = {
      id: row.id,
      name: row.name,
      description: row.description,
      price: row.price,
      category: row.category,
      imageUrl: row.image_url,
      stock: row.stock,
      createdAt: row.created_at
    };

    return res.status(200).json(product);

  } catch (error) {
    console.error('Get product error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '获取商品详情失败'
    };
    return res.status(500).json(errorResponse);
  }
});

// GET /api/products/categories - 获取所有商品分类
router.get('/meta/categories', (req: Request, res: Response) => {
  try {
    const db = getDb();
    const rows = db.prepare(`
      SELECT DISTINCT category 
      FROM products 
      ORDER BY category
    `).all() as { category: string }[];

    const categories = rows.map(row => row.category);

    return res.status(200).json(categories);

  } catch (error) {
    console.error('Get categories error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '获取分类列表失败'
    };
    return res.status(500).json(errorResponse);
  }
});

// POST /api/products - 创建商品（管理端）
router.post('/', (req: Request, res: Response) => {
  try {
    const { name, description, price, category, imageUrl, stock }: CreateProductRequest = req.body;

    // 参数验证
    if (!name || price === undefined || !category) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '商品名称、价格和分类不能为空'
      };
      return res.status(400).json(error);
    }

    if (price < 0) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '商品价格不能为负数'
      };
      return res.status(400).json(error);
    }

    const db = getDb();
    const result = db.prepare(`
      INSERT INTO products (name, description, price, category, image_url, stock, created_at)
      VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
    `).run(
      name,
      description || '',
      price,
      category,
      imageUrl || '',
      stock || 0
    );

    const newProduct: Product = {
      id: result.lastInsertRowid as number,
      name,
      description: description || '',
      price,
      category,
      imageUrl: imageUrl || '',
      stock: stock || 0,
      createdAt: new Date().toISOString()
    };

    return res.status(201).json(newProduct);

  } catch (error) {
    console.error('Create product error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '创建商品失败'
    };
    return res.status(500).json(errorResponse);
  }
});

// PUT /api/products/:id - 更新商品
router.put('/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const productId = parseInt(id, 10);

    if (isNaN(productId)) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '无效的商品ID'
      };
      return res.status(400).json(error);
    }

    const { name, description, price, category, imageUrl, stock }: Partial<CreateProductRequest> = req.body;

    const db = getDb();

    // 检查商品是否存在
    const existingProduct = db.prepare('SELECT id FROM products WHERE id = ?').get(productId);
    if (!existingProduct) {
      const error: ApiError = {
        code: 'PRODUCT_NOT_FOUND',
        message: '商品不存在'
      };
      return res.status(404).json(error);
    }

    // 构建更新语句
    const updates: string[] = [];
    const params: (string | number)[] = [];

    if (name !== undefined) {
      updates.push('name = ?');
      params.push(name);
    }
    if (description !== undefined) {
      updates.push('description = ?');
      params.push(description);
    }
    if (price !== undefined) {
      if (price < 0) {
        const error: ApiError = {
          code: 'INVALID_PARAMS',
          message: '商品价格不能为负数'
        };
        return res.status(400).json(error);
      }
      updates.push('price = ?');
      params.push(price);
    }
    if (category !== undefined) {
      updates.push('category = ?');
      params.push(category);
    }
    if (imageUrl !== undefined) {
      updates.push('image_url = ?');
      params.push(imageUrl);
    }
    if (stock !== undefined) {
      updates.push('stock = ?');
      params.push(stock);
    }

    if (updates.length === 0) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '没有提供任何更新字段'
      };
      return res.status(400).json(error);
    }

    params.push(productId);

    db.prepare(`
      UPDATE products 
      SET ${updates.join(', ')}
      WHERE id = ?
    `).run(...params);

    // 获取更新后的商品
    const row = db.prepare(`
      SELECT id, name, description, price, category, image_url, stock, created_at 
      FROM products 
      WHERE id = ?
    `).get(productId) as {
      id: number;
      name: string;
      description: string;
      price: number;
      category: string;
      image_url: string;
      stock: number;
      created_at: string;
    };

    const product: Product = {
      id: row.id,
      name: row.name,
      description: row.description,
      price: row.price,
      category: row.category,
      imageUrl: row.image_url,
      stock: row.stock,
      createdAt: row.created_at
    };

    return res.status(200).json(product);

  } catch (error) {
    console.error('Update product error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '更新商品失败'
    };
    return res.status(500).json(errorResponse);
  }
});

// DELETE /api/products/:id - 删除商品
router.delete('/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const productId = parseInt(id, 10);

    if (isNaN(productId)) {
      const error: ApiError = {
        code: 'INVALID_PARAMS',
        message: '无效的商品ID'
      };
      return res.status(400).json(error);
    }

    const db = getDb();

    // 检查商品是否存在
    const existingProduct = db.prepare('SELECT id FROM products WHERE id = ?').get(productId);
    if (!existingProduct) {
      const error: ApiError = {
        code: 'PRODUCT_NOT_FOUND',
        message: '商品不存在'
      };
      return res.status(404).json(error);
    }

    // 删除商品
    db.prepare('DELETE FROM products WHERE id = ?').run(productId);

    return res.status(200).json({ success: true, message: '商品删除成功' });

  } catch (error) {
    console.error('Delete product error:', error);
    const errorResponse: ApiError = {
      code: 'INTERNAL_ERROR',
      message: '删除商品失败'
    };
    return res.status(500).json(errorResponse);
  }
});

export default router;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import type { AppMountOptions } from './types';

/**
 * 挂载 React 应用到 DOM
 * @param options 挂载配置选项
 */
function mountApp(options: AppMountOptions = {}): void {
  const { rootElementId = 'root' } = options;

  const rootElement = document.getElementById(rootElementId);

  if (!rootElement) {
    throw new Error(`Root element with id "${rootElementId}" not found`);
  }

  const root = ReactDOM.createRoot(rootElement);

  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
}

