import React, { useState, useEffect, createContext, useContext } from 'react';
import Login from './pages/Login';
import ProductList from './pages/ProductList';
import type { AppProps, RouteConfig, User, LoginResponse } from './types';

// ============================================================
// [AUTH CONTEXT] 认证状态管理
// ============================================================

interface AuthContextType {
  user: User | null;
  token: string | null;
  login: (response: LoginResponse) => void;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

/**
 * 认证状态 Provider
 */
function AuthProvider({ children }: { children: React.ReactNode }): JSX.Element {
  const [user, setUser] = useState<User | null>(null);
  const [token, setToken] = useState<string | null>(() => {
    return localStorage.getItem('token');
  });

  useEffect(() => {
    // 从 localStorage 恢复用户信息
    const storedUser = localStorage.getItem('user');
    if (storedUser && token) {
      try {
        setUser(JSON.parse(storedUser));
      } catch {
        localStorage.removeItem('user');
        localStorage.removeItem('token');
        setToken(null);
      }
    }
  }, [token]);

  const login = (response: LoginResponse): void => {
    setToken(response.token);
    setUser(response.user);
    localStorage.setItem('token', response.token);
    localStorage.setItem('user', JSON.stringify(response.user));
  };

  const logout = (): void => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    localStorage.removeItem('user');
  };

  const value: AuthContextType = {
    user,
    token,
    login,
    logout,
    isAuthenticated: !!token && !!user,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

/**
 * 使用认证上下文
 */
function useAuth(): AuthContextType {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// ============================================================
// [ROUTE COMPONENT] 路由组件
// ============================================================

interface RouteComponentProps {
  routes: RouteConfig[];
  currentPath: string;
}

function Route({ routes, currentPath }: RouteComponentProps): JSX.Element | null {
  // 匹配路由
  const matchedRoute = routes.find((route) => {
    // 简单的路径匹配（支持精确匹配）
    return route.path === currentPath;
  });

  if (!matchedRoute) {
    return (
      <div className="error-page">
        <h1>404</h1>
        <p>Page not found</p>
      </div>
    );
  }

  return <>{matchedRoute.element}</>;
}

// ============================================================
// [NAVIGATION] 导航组件
// ============================================================

function Navigation(): JSX.Element {
  const { user, logout, isAuthenticated } = useAuth();

  return (
    <nav className="navigation">
      <div className="nav-brand">
        <a href="/">电商平台</a>
      </div>
      <div className="nav-links">
        <a href="/" className="nav-link">首页</a>
        <a href="/products" className="nav-link">商品列表</a>
      </div>
      <div className="nav-auth">
        {isAuthenticated ? (
          <>
            <span className="user-info">欢迎, {user?.username}</span>
            <button onClick={logout} className="btn-logout">
              退出登录
            </button>
          </>
        ) : (
          <a href="/login" className="btn-login">
            登录
          </a>
        )}
      </div>
    </nav>
  );
}

// ============================================================
// [PROTECTED ROUTE] 需要认证的路由包装
// ============================================================

interface ProtectedRouteProps {
  children: React.ReactNode;
}

function ProtectedRoute({ children }: ProtectedRouteProps): JSX.Element {
  const { isAuthenticated } = useAuth();

  if (!isAuthenticated) {
    // 重定向到登录页
    window.location.href = '/login';
    return (
      <div className="loading">
        <p>正在跳转登录页...</p>
      </div>
    );
  }

  return <>{children}</>;
}

// ============================================================
// [MAIN APP COMPONENT] 主应用组件
// ============================================================

/**
 * App 根组件
 * 提供全局认证状态和路由功能
 */
function App({ initialPath }: AppProps = {}): JSX.Element {
  const [currentPath, setCurrentPath] = useState<string>(
    initialPath || window.location.pathname
  );

  // 监听浏览器前进后退按钮
  useEffect(() => {
    const handlePopState = (): void => {
      setCurrentPath(window.location.pathname);
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // 路由配置
  const routes: RouteConfig[] = [
    {
      path: '/',
      element: (
        <div className="home-page">
          <h1>欢迎来到电商平台</h1>
          <p>浏览我们的精选商品</p>
          <a href="/products" className="btn-primary">
            浏览商品
          </a>
        </div>
      ),
      protected: false,
    },
    {
      path: '/login',
      element: <Login />,
      protected: false,
    },
    {
      path: '/products',
      element: <ProductList />,
      protected: false,
    },
  ];

  // 导航到指定路径
  const navigate = (path: string): void => {
    window.history.pushState({}, '', path);
    setCurrentPath(path);
  };

  return (
    <AuthProvider>
      <div className="app">
        <Navigation />
        <main className="main-content">
          <Route routes={routes} currentPath={currentPath} />
        </main>
        <footer className="footer">
          <p>&copy; 2024 电商平台. All rights reserved.</p>
        </footer>
      </div>
    </AuthProvider>
  );
}

export default App;

// 导出子组件和工具供测试使用
export { App, AuthProvider, useAuth, Route, ProtectedRoute };

import React from 'react';
import type { Product, HomePageData, HomePageProps } from '../types';

/**
 * 首页组件
 * 展示推荐商品和分类导航
 */
const Home: React.FC<HomePageProps> = ({ data, isLoading = false, error = null }) => {
  const featuredProducts: Product[] = data?.featuredProducts || [];
  const categories: string[] = data?.categories || [];

  if (isLoading) {
    return (
      <div className="home-page loading">
        <div className="loading-spinner">
          <span>加载中...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="home-page error">
        <div className="error-message">
          <h2>出错了</h2>
          <p>{error}</p>
        </div>
      </div>
    );
  }

