import React, { useState } from 'react';
import type { LoginFormData, LoginFormErrors, LoginPageProps, LoginResponse, ApiError } from '../types';

/**
 * 登录页组件
 * 提供用户登录表单和认证功能
 */
const Login: React.FC<LoginPageProps> = ({
  onLoginSuccess,
  onLoginError
}) => {
  const [formData, setFormData] = useState<LoginFormData>({
    username: '',
    password: ''
  });
  const [errors, setErrors] = useState<LoginFormErrors>({});
  const [isLoading, setIsLoading] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  /**
   * 验证表单数据
   */
  const validateForm = (): boolean => {
    const newErrors: LoginFormErrors = {};

    if (!formData.username.trim()) {
      newErrors.username = '请输入用户名';
    } else if (formData.username.length < 3) {
      newErrors.username = '用户名至少3个字符';
    }

    if (!formData.password) {
      newErrors.password = '请输入密码';
    } else if (formData.password.length < 6) {
      newErrors.password = '密码至少6个字符';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  /**
   * 处理输入变化
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value
    }));

    // 清除对应字段的错误
    if (errors[name as keyof LoginFormErrors]) {
      setErrors((prev) => ({
        ...prev,
        [name]: undefined
      }));
    }
  };

  /**
   * 处理表单提交
   */
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitError(null);

    if (!validateForm()) {
      return;
    }

    setIsLoading(true);

    try {
      const response = await fetch('/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (!response.ok) {
        const error: ApiError = {
          code: data.code || 'LOGIN_FAILED',
          message: data.message || '登录失败'
        };
        setSubmitError(error.message);
        onLoginError?.(error);
        return;
      }

      const loginResponse: LoginResponse = {
        token: data.token,
        user: data.user
      };

      // 保存 token 到 localStorage
      localStorage.setItem('authToken', loginResponse.token);
      localStorage.setItem('user', JSON.stringify(loginResponse.user));

      onLoginSuccess?.(loginResponse);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : '网络错误，请稍后重试';
      setSubmitError(errorMessage);
      const apiError: ApiError = {
        code: 'NETWORK_ERROR',
        message: errorMessage
      };
      onLoginError?.(apiError);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <h1>用户登录</h1>
          <p>欢迎回来，请登录您的账号</p>
        </div>

        <form className="login-form" onSubmit={handleSubmit}>
          {submitError && (
            <div className="error-banner">
              {submitError}
            </div>
          )}

          <div className="form-group">
            <label htmlFor="username">用户名</label>
            <input
              type="text"
              id="username"
              name="username"
              value={formData.username}
              onChange={handleChange}
              placeholder="请输入用户名"
              disabled={isLoading}
              autoComplete="username"
            />
            {errors.username && (
              <span className="field-error">{errors.username}</span>
            )}
          </div>

          <div className="form-group">
            <label htmlFor="password">密码</label>
            <input
              type="password"
              id="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="请输入密码"
              disabled={isLoading}
              autoComplete="current-password"
            />
            {errors.password && (
              <span className="field-error">{errors.password}</span>
            )}
          </div>

          <button
            type="submit"
            className="submit-button"
            disabled={isLoading}
          >
            {isLoading ? '登录中...' : '登录'}
          </button>

          <div className="login-footer">
            <span>还没有账号？</span>
            <a href="/register">立即注册</a>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useCallback } from 'react';
import type { Product, ProductListPageProps, ProductListState, CategoryOption } from '../types';

/**
 * 商品列表页组件
 * 展示商品列表，支持分类筛选和分页
 */
const ProductList: React.FC<ProductListPageProps> = ({
  initialCategory = ''
}) => {
  const [state, setState] = useState<ProductListState>({
    products: [],
    total: 0,
    currentPage: 1,
    limit: 12,
    category: initialCategory || undefined,
    isLoading: false,
    error: null
  });

  const [categories] = useState<CategoryOption[]>([
    { label: '全部', value: '' },
    { label: '电子产品', value: 'electronics' },
    { label: '服装', value: 'clothing' },
    { label: '图书', value: 'books' },
    { label: '食品', value: 'food' },
    { label: '家居', value: 'home' }
  ]);

  /**
   * 获取商品列表数据
   */
  const fetchProducts = useCallback(async () => {
    setState((prev) => ({ ...prev, isLoading: true, error: null }));

    try {
      const params = new URLSearchParams({
        page: state.currentPage.toString(),
        limit: state.limit.toString()
      });

      if (state.category) {
        params.append('category', state.category);
      }

      const response = await fetch(`/api/products?${params.toString()}`);

      if (!response.ok) {
        throw new Error('获取商品列表失败');
      }

      const data = await response.json();

      setState((prev) => ({
        ...prev,
        products: data.products || [],
        total: data.total || 0,
        isLoading: false
      }));
    } catch (err) {
      setState((prev) => ({
        ...prev,
        error: err instanceof Error ? err.message : '加载失败，请稍后重试',
        isLoading: false
      }));
    }
  }, [state.currentPage, state.limit, state.category]);

  useEffect(() => {
    fetchProducts();
  }, [fetchProducts]);

  /**
   * 处理分类筛选变化
   */
  const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const category = e.target.value;
    setState((prev) => ({
      ...prev,
      category: category || undefined,
      currentPage: 1
    }));
  };

  /**
   * 处理分页变化
   */
  const handlePageChange = (page: number) => {
    if (page < 1 || page > totalPages) return;
    setState((prev) => ({ ...prev, currentPage: page }));
  };

  /**
   * 计算总页数
   */
  const totalPages = Math.ceil(state.total / state.limit);

  /**
   * 格式化价格
   */
  const formatPrice = (price: number): string => {
    return `¥${price.toFixed(2)}`;
  };

  return (
    <div className="product-list-page">
      <div className="page-header">
        <h1>商品列表</h1>
        <p>浏览所有商品，发现心仪好物</p>
      </div>

      {/* 筛选区域 */}
      <div className="filter-section">
        <div className="filter-group">
          <label htmlFor="category-filter">分类筛选：</label>
          <select
            id="category-filter"
            value={state.category || ''}
            onChange={handleCategoryChange}
            disabled={state.isLoading}
          >
            {categories.map((cat) => (
              <option key={cat.value} value={cat.value}>
                {cat.label}
              </option>
            ))}
          </select>
        </div>

        <div className="result-count">
          共 {state.total} 件商品
        </div>
      </div>

      {/* 加载状态 */}
      {state.isLoading && (
        <div className="loading-overlay">
          <div className="loading-spinner">
            <span>加载中...</span>
          </div>
        </div>
      )}

      {/* 错误状态 */}
      {state.error && (
        <div className="error-message">
          <p>{state.error}</p>
          <button onClick={fetchProducts}>重试</button>
        </div>
      )}

      {/* 商品列表 */}
      {!state.error && (
        <div className="products-grid">
          {state.products.length > 0 ? (
            state.products.map((product) => (
              <div key={product.id} className="product-card">
                <div className="product-image-wrapper">
                  <img
                    src={product.imageUrl}
                    alt={product.name}
                    className="product-image"
                    loading="lazy"
                  />
                  <span className="product-category-badge">
                    {product.category}
                  </span>
                </div>
                <div className="product-info">
                  <h3 className="product-name">{product.name}</h3>
                  <p className="product-description">
                    {product.description.length > 60
                      ? `${product.description.slice(0, 60)}...`
                      : product.description}
                  </p>
                  <div className="product-price">
                    {formatPrice(product.price)}
                  </div>
                  <div className="product-stock">
                    库存: {product.stock}
                  </div>
                  <div className="product-actions">
                    <button className="btn-detail">
                      查看详情
                    </button>
                    <button className="btn-add-cart">
                      加入购物车
                    </button>
                  </div>
                </div>
              </div>
            ))
          ) : !state.isLoading ? (
            <div className="no-products">
              <p>暂无商品</p>
            </div>
          ) : null}
        </div>
      )}

      {/* 分页组件 */}
      {!state.error && state.total > 0 && (
        <div className="pagination">
          <button
            className="page-btn"
            onClick={() => handlePageChange(state.currentPage - 1)}
            disabled={state.currentPage === 1 || state.isLoading}
          >
            上一页
          </button>

          <div className="page-numbers">
            {Array.from({ length: totalPages }, (_, i) => i + 1)
              .filter((page) => {
                const distance = Math.abs(page - state.currentPage);
                return distance <= 2 || page === 1 || page === totalPages;
              })
              .map((page, index, array) => {
                const prevPage = array[index - 1];
                const showEllipsis = prevPage && page - prevPage > 1;

                return (
                  <React.Fragment key={page}>
                    {showEllipsis && <span className="ellipsis">...</span>}
                    <button
                      className={`page-number ${
                        page === state.currentPage ? 'active' : ''
                      }`}
                      onClick={() => handlePageChange(page)}
                      disabled={state.isLoading}
                    >
                      {page}
                    </button>
                  </React.Fragment>
                );
              })}
          </div>

          <button
            className="page-btn"
            onClick={() => handlePageChange(state.currentPage + 1)}
            disabled={state.currentPage === totalPages || state.isLoading}
          >
            下一页
          </button>
        </div>
      )}
    </div>
  );
};

